def is_valid_bst_inorder(root: Optional["TreeNode"]) -> bool:
    inorder: List[int] = []

    def traverse(node: Optional["TreeNode"]) -> None:
        if node is None:
            return
        traverse(node.left)
        inorder.append(node.val)
        traverse(node.right)

    traverse(root)
    return all(inorder[i] < inorder[i + 1] for i in range(len(inorder) - 1))

