public boolean isValidBST(TreeNode root) {
    Stack stack = new Stack<>();
    TreeNode prev = null;
    TreeNode current = root;

    while (current != null || !stack.isEmpty()) {
        while (current != null) {
            stack.push(current);
            current = current.left;
        }

        current = stack.pop();

        if (prev != null && current.val <= prev.val) {
            return false;
        }

        prev = current;
        current = current.right;
    }

    return true;
}
